import pandas as pd

def solve_query(transactions, products, customers):
    # Ensure the necessary columns exist
    if 'CustomerID' not in transactions.columns or 'Currency' not in customers.columns:
        return pd.DataFrame(columns=['ProductID', 'Description'])

    # Filter customers with Currency = 'EUR'
    euro_customers = customers[customers['Currency'] == 'EUR']

    # Merge transactions with euro_customers to filter relevant transactions
    merged_transactions = pd.merge(transactions, euro_customers, on='CustomerID', how='inner')

    # Merge with products to get product descriptions
    result = pd.merge(merged_transactions, products, left_on='ProductID', right_on='ProductID', how='inner')

    # Select distinct ProductID and Description
    result = result[['ProductID', 'Description']].drop_duplicates()

    return result

